import type { Metadata } from "next";
import { Inter, JetBrains_Mono, DM_Sans } from "next/font/google";
import "./globals.css";
import { ThemeProvider } from "@/components/providers/ThemeProvider";
import { Navbar } from "@/components/layout/Navbar";
import { Footer } from "@/components/layout/Footer";

const inter = Inter({
  variable: "--font-inter",
  subsets: ["latin"],
  display: "swap",
  weight: ["400", "500", "600", "700", "800"],
});

const dmSans = DM_Sans({
  variable: "--font-matter",
  subsets: ["latin"],
  display: "swap",
  weight: ["400", "500"],
});

const jetbrains = JetBrains_Mono({
  variable: "--font-jetbrains",
  subsets: ["latin"],
  display: "swap",
  weight: ["400", "500"],
});

export const metadata: Metadata = {
  metadataBase: new URL("https://gunmetalapp.vercel.app"),
  title: {
    default: "Gunmetal",
    template: "%s | Gunmetal",
  },
  description:
    "One local API. Every AI provider. Gunmetal turns your AI subscriptions into a unified endpoint.",
  keywords: [
    "AI",
    "inference",
    "local API",
    "OpenAI compatible",
    "AI gateway",
    "model routing",
  ],
  openGraph: {
    type: "website",
    locale: "en_US",
    url: "https://gunmetalapp.vercel.app",
    siteName: "Gunmetal",
    title: "Gunmetal — One Local API. Every AI Provider.",
    description:
      "Gunmetal turns your AI subscriptions into a unified endpoint. Route, control, and observe every request.",
  },
  twitter: {
    card: "summary_large_image",
    title: "Gunmetal — One Local API. Every AI Provider.",
    description:
      "Gunmetal turns your AI subscriptions into a unified endpoint. Route, control, and observe every request.",
  },
  icons: {
    icon: "/icon.svg",
  },
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en" data-theme="dark" data-scroll-behavior="smooth">
      <body
        className={`${inter.variable} ${jetbrains.variable} ${dmSans.variable}`}
        style={{ colorScheme: "dark" }}
      >
        <ThemeProvider>
          <div className="min-h-screen flex flex-col bg-[var(--bg)] text-[var(--text)] selection:bg-[#faf9f6] selection:text-[#1a1a19] relative overflow-hidden">
            <a
              href="#main"
              className="sr-only focus:not-sr-only focus:fixed focus:top-3 focus:left-3 focus:z-[200] focus:rounded-lg focus:bg-[rgba(14,14,13,0.95)] focus:px-3 focus:py-2 focus:text-[14px] focus:text-[var(--text)] focus:outline-none focus-visible:ring-2 focus-visible:ring-[rgba(250,249,246,0.18)]"
            >
              Skip to content
            </a>
            <Navbar />
            <main id="main" className="relative z-10 flex-1 flex flex-col">
              {children}
            </main>
            <Footer />
          </div>
        </ThemeProvider>
      </body>
    </html>
  );
}

@import "tailwindcss";

@layer theme {
  :root {
    --bg: #0e0e0d;
    --surface: #181816;
    --surface-elevated: #222220;
    --text: #faf9f6;
    --text-secondary: #afaeac;
    --text-muted: #868584;
    --text-faint: #666469;
    --border: rgba(226, 226, 226, 0.18);
    --border-strong: rgba(226, 226, 226, 0.35);
    --frosted: rgba(255, 255, 255, 0.04);
    --font-matter: var(--font-dm-sans), -apple-system, BlinkMacSystemFont, sans-serif;
    --font-sans: var(--font-inter), -apple-system, BlinkMacSystemFont, sans-serif;
    --font-mono: var(--font-jetbrains), ui-monospace, monospace;
    --duration-normal: 400ms;
    --ease-out: cubic-bezier(0.22, 1, 0.36, 1);
  }
}

@layer base {
  *,
  *::before,
  *::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
  }

  html {
    scroll-behavior: smooth;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    text-rendering: optimizeLegibility;
  }

  body {
    min-height: 100vh;
    overflow-x: hidden;
    background-color: var(--bg);
    color: var(--text);
    font-family: var(--font-matter);
    font-size: 18px;
    font-weight: 400;
    line-height: 1.4;
  }

  ::selection {
    background-color: rgba(250, 249, 246, 0.15);
    color: var(--text);
  }

  :focus-visible {
    outline: 1px solid var(--border-strong);
    outline-offset: 2px;
  }

  ::-webkit-scrollbar {
    width: 5px;
    height: 5px;
  }

  ::-webkit-scrollbar-track {
    background: transparent;
  }

  ::-webkit-scrollbar-thumb {
    background: var(--border-strong);
    border-radius: 10px;
  }

  ::-webkit-scrollbar-thumb:hover {
    background: rgba(226, 226, 226, 0.5);
  }

  a {
    color: inherit;
    text-decoration: none;
  }

  img {
    display: block;
    max-width: 100%;
    height: auto;
  }

  h1,
  h2,
  h3,
  h4,
  h5,
  h6 {
    font-family: var(--font-matter);
    font-weight: 400;
    letter-spacing: -0.02em;
    line-height: 1.1;
  }
}

@keyframes fade-in {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@layer utilities {
  .animate-in {
    animation: fade-in var(--duration-normal) var(--ease-out) both;
  }
}

