          setBanner("Paste a Gunmetal key first.", "danger");
          return;
        }
        if (!model) {
          setBanner("Sync at least one model first.", "danger");
          return;
        }
        if (!content) {
          setBanner("Enter a message before sending the request.", "danger");
          return;
        }

        if (historyMode === "single") {
          appState.playground.messages = [];
        }

        appState.playground.key = key;
        appState.playground.model = model;
        appState.playground.mode = mode;
        appState.playground.historyMode = historyMode;
        appState.playground.running = true;
        appState.playground.usage = null;
        pushPlaygroundMessage("user", content);
        $("playground-input").value = "";
        renderPlayground();

        try {
          await runPlayground(mode, key, model, appState.playground.messages);
          appState.selectedLogId = null;
          setBanner("Playground request completed.", "success");
          await loadState();
          await wait(350);
          appState.selectedLogId = null;
          await loadState();
        } catch (error) {
          appState.playground.messages = appState.playground.messages.slice(
            0,
            Math.max(0, appState.playground.messages.length - 2),
