            health: Some("{\"status\":\"ok\"}".to_owned()),
            home: None,
            note: Some(
                "Gunmetal is running, but not under managed daemon state. Stop the foreground `gunmetal serve` process directly.".to_owned(),
            ),
        },
        super::ServiceVerb::Stop,
    )
    .unwrap();

